#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int head[N],des[N<<1],nxt[N<<1],cgt,a[N],P[N],p;bool col[N],vis[N];
inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
int mxs[N],siz[N],dep[N],fa[N],idx[N<<1],ql[N],qr[N],cdt,top[N],n;
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline void dfs0(int u=1,int f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;
	grep(u,i)if(des[i]!=f)
	{
		int v=des[i];dfs0(v,u);siz[u]+=siz[v];
		mx<siz[v]?mx=siz[mxs[u]=v]:0; 
	}
}
inline void dfs1(int u=1,int fa=0,int tp=1)
{
	top[u]=tp;idx[ql[u]=++cdt]=u;if(mxs[u])dfs1(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs1(des[i],u,des[i]);idx[qr[u]=++cdt]=u;
}
inline int LCA(int u,int v)
{
	while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
	return dep[u] < dep[v] ? u : v ; 
}
typedef long long LL;
struct NN{int l,r,idx,lc;}q[N];int c[N][2],L,R;LL Ans,ans[N];
inline void ins(int u)
{
	if(vis[u]){vis[u]=false;Ans+=c[a[u]][col[u]^1];++c[a[u]][col[u]];}
	else{vis[u]=true;Ans-=c[a[u]][col[u]^1];--c[a[u]][col[u]];}
}
int main()
{
	n=read();rep(1,n,i)col[i]=read();rep(1,n,i)a[i]=P[i]=read();
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);
	rep(2,n,i)ins(read(),read());dfs0();dfs1();
	int Q=read();rep(1,Q,i)
	{
		int u=read(),v=read(),lc=LCA(u,v);if(ql[u]>ql[v])std::swap(u,v);
		if(lc==u||lc==v)q[i]={ql[u],ql[v],i,0};else q[i]={qr[u],ql[v],i,lc};
	}
	std::sort(q+1,q+Q+1,[&](const NN&x,const NN&y){return (x.l>>8)==(y.l>>8)?((x.l>>8&1)?x.r>y.r:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=L-1;Ans=0;rep(1,Q,i)
	{
		while(R<q[i].r)ins(idx[++R]);while(L>q[i].l)ins(idx[--L]);
		while(R>q[i].r)ins(idx[R--]);while(L<q[i].l)ins(idx[L++]);
		if(q[i].lc)ins(q[i].lc);ans[q[i].idx]=Ans;if(q[i].lc)ins(q[i].lc);
	}
	rep(1,Q,i)printf("%lld\n",ans[i]);return 0;
}
